sql:
SELECT COUNT(DISTINCT customer_id) AS num_customers
FROM online_transactions
WHERE transaction_date BETWEEN '2022-01-01' AND '2022-03-31';

SELECT COUNT(visit_id) AS total_visits
FROM online_visits
WHERE customer_id = 'customer_id_goes_here';

SELECT * 
FROM customers 
WHERE customer_id IN (
    SELECT DISTINCT customer_id 
    FROM online_transactions
) OR customer_id IN (
    SELECT DISTINCT customer_id 
    FROM store_transactions
);

SELECT ot.customer_id, SUM(ot.amount_spent) AS total_amount_spent
FROM online_transactions ot
GROUP BY ot.customer_id;

SELECT COUNT(DISTINCT c.customer_id) AS unique_voyagers, AVG(c.age) AS average_age
FROM customers c
JOIN online_transactions ot ON c.customer_id = ot.customer_id;

SELECT customer_id, SUM(visit_duration) AS total_visit_duration
FROM online_visits
GROUP BY customer_id;

SELECT c.customer_id, c.age, c.email, c.loyalty_program_id, c.preferred_communication_channel, c.created_at, c.updated_at
FROM customers c
WHERE (
    (SELECT COALESCE(SUM(ot.amount_spent), 0) FROM online_transactions ot WHERE ot.customer_id = c.customer_id) +
    (SELECT COALESCE(SUM(st.amount_spent), 0) FROM store_transactions st WHERE st.customer_id = c.customer_id)
) > 1000;

SELECT 
    (SELECT COUNT(DISTINCT customer_id) FROM online_transactions) AS online_customers,
    (SELECT COUNT(DISTINCT customer_id) FROM store_transactions) AS in_store_customers;

SELECT COUNT(*)
FROM customers
WHERE credit_score < 600 AND customer_id NOT IN (SELECT customer_id FROM online_transactions);

SELECT customer_id FROM online_transactions
INTERSECT
SELECT customer_id FROM store_transactions;
